# Prometheus query helpers for GenAI capacity metrics
from prometheus_api_client import PrometheusConnect
from dataclasses import dataclass

prom = PrometheusConnect(url='http://prometheus.internal:9090')

@dataclass
class CapacitySnapshot:
    model: str
    request_rate_rps: float        # HTTP requests/second
    prompt_tokens_per_s: float     # input tokens/second
    completion_tokens_per_s: float # output tokens/second
    gpu_util_pct: float            # mean MFU across replicas
    replica_count: int

    @property
    def total_tokens_per_s(self) -> float:
        return self.prompt_tokens_per_s + self.completion_tokens_per_s

def fetch_snapshot(model: str, window: str = '5m') -> CapacitySnapshot:
    def q(expr):
        result = prom.custom_query(expr)
        return float(result[0]['value'][1]) if result else 0.0

    return CapacitySnapshot(
        model=model,
        request_rate_rps=q(
            f'sum(rate(llm_requests_total{{model="{model}"}}[{window}]))'
        ),
        prompt_tokens_per_s=q(
            f'sum(rate(llm_prompt_tokens_total{{model="{model}"}}[{window}]))'
        ),
        completion_tokens_per_s=q(
            f'sum(rate(llm_completion_tokens_total{{model="{model}"}}[{window}]))'
        ),
        gpu_util_pct=q(
            f'avg(gpu_mfu_percent{{model="{model}"}})'
        ),
        replica_count=int(q(
            f'count(up{{job="llm-server",model="{model}"}})'
        )),
    )

import json, urllib.request
from datetime import datetime

CAPACITY = {
    'gpt4-class':    4_800,    # 4 A100 80GB nodes x ~1.2k tok/s
    'gpt35-class':  28_000,    # 4 nodes x 7k tok/s (7B distilled)
    'embedding-ada': 120_000,  # 2 nodes, high throughput
}

def format_runway_line(model: str, result) -> str:
    if result.runway_days is None:
        icon, detail = ':large_green_circle:', 'demand flat / declining'
    elif result.runway_days < 14:
        icon = ':red_circle:'
        detail = f'*{result.runway_days:.0f}d -- IMMEDIATE ACTION*'
    elif result.runway_days < 30:
        icon = ':large_yellow_circle:'
        detail = f'{result.runway_days:.0f}d -- open provisioning ticket'
    else:
        icon = ':large_green_circle:'
        detail = f'{result.runway_days:.0f}d'
    return f'{icon} *{model}*: util={result.utilization_pct:.0f}%, runway={detail}'

def post_weekly_capacity_report(results: dict, slack_webhook: str):
    lines = ['*Weekly GenAI Capacity Runway Report*', '']
    for model, result in results.items():
        lines.append(format_runway_line(model, result))
    lines += [
        '',
        f'_Generated {datetime.utcnow().strftime("%Y-%m-%d %H:%M UTC")}_',
        '_Provision to upper-bound forecast. GPU lead time = 14d._',
    ]
    payload = json.dumps({'text': chr(10).join(lines)}).encode()
    req = urllib.request.Request(
        slack_webhook, data=payload,
        headers={'Content-Type': 'application/json'}
    )
    urllib.request.urlopen(req)
